qss:
QWidget { background: #11131a; color: #e8eaee; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #11131a; }
QGroupBox { background: #181b24; border: 1px solid #394150; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #3b82f6; }
QTabWidget::pane { border: 1px solid #394150; background: #181b24; }
QTabBar::tab { background: #10131a; color: #e8eaee; padding: 8px 14px; border: 1px solid #394150; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #1d4ed8; color: #ffffff; font-weight: bold; }
QTabBar::tab:hover { background: #263244; color: #ffffff; }
QPushButton { background: #263244; color: #ffffff; border: 1px solid #3b82f6; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #3b82f6; color: #ffffff; }
QPushButton:disabled { background: #59606f; color: #10131a; border-color: #394150; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #10131a; color: #e8eaee; border: 1px solid #394150; border-radius: 5px; padding: 5px; selection-background-color: #3b82f6; selection-color: #ffffff; }
QComboBox QAbstractItemView { background: #10131a; color: #e8eaee; selection-background-color: #3b82f6; selection-color: #ffffff; border: 1px solid #394150; }
QTableWidget { background: #10131a; alternate-background-color: #181b24; color: #e8eaee; gridline-color: #394150; selection-background-color: #3b82f6; selection-color: #ffffff; }
QHeaderView::section { background: #1d4ed8; color: #ffffff; padding: 6px; border: 1px solid #394150; font-weight: bold; }
QScrollBar:vertical { background: #181b24; width: 14px; }
QScrollBar::handle:vertical { background: #3b82f6; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #181b24; height: 14px; }
QScrollBar::handle:horizontal { background: #3b82f6; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #e8eaee; }
